const wrapper = document.getElementById('tags-wrapper');
const tagInput = document.getElementById('tag-input');
const tagsSet = new Set();

function createTag(val) {
  const label = val.trim();
  if (!label || tagsSet.has(label.toLowerCase())) return;

  tagsSet.add(label.toLowerCase());

  const span = document.createElement('span');
  span.className = 'flex items-center gap-1.5 px-2.5 py-1 bg-indigo-600 text-xs font-bold rounded-md border border-indigo-500 select-none';

  const textNode = document.createTextNode(label);
  span.appendChild(textNode);

  const removeBtn = document.createElement('button');
  removeBtn.className = 'hover:text-red-300 font-bold focus:outline-none';
  removeBtn.textContent = '×';
  removeBtn.addEventListener('click', () => {
    tagsSet.delete(label.toLowerCase());
    span.remove();
    tagInput.focus();
  });

  span.appendChild(removeBtn);
  wrapper.insertBefore(span, tagInput);
}

tagInput.addEventListener('keydown', (e) => {
  if (e.key === 'Enter' || e.key === ',') {
    e.preventDefault();
    const val = tagInput.value.replace(/,/g, '').trim();
    if (val) {
      createTag(val);
      tagInput.value = '';
    }
  }
});
